            super::gemini::spawn_gemini_task(
                optimized_prompt,
                project_dir,
                task_id,
                on_event,
                state.clone(),
            )
            .await?
        }
        "codex" => {
            super::codex::spawn_codex_task(
                optimized_prompt,
                project_dir,
                task_id,
                on_event,
                state.clone(),
            )
            .await?
        }
        _ => return Err(format!("Unknown tool: {}", tool_name)),
    };

