                entry.path.to_string_lossy().to_string()
            } else {
                match worktree_manager.create_for_task(dag_id) {
                    Ok(entry) => {
                        let cwd = entry.path.to_string_lossy().to_string();
                        emit_orch(&on_event, "worktree_created", serde_json::json!({
                            "dag_id": dag_id,
                            "task_id": entry.task_id,
